ectionModule -->\n\nDeviceMapper->DeviceDetectionModule\n\n\n\n\n\nFingerprintService\n\nFingerprintService\n\nDeviceDetectionModule -->\n\nFingerprintService->DeviceDetectionModule\n\n\n\n\n\nUserAgentParser\n\nUserAgentParser\n\nDeviceDetectionModule -->\n\nUserAgentParser->DeviceDetectionModule\n\n\n\nFeaturesModule -->\n\nSecurityModule->FeaturesModule\n\n\n\n\n\nDeviceDetectionModule \n\nDeviceDetectionModule \n\nDeviceDetectionModule  -->\n\nSecurityModule->DeviceDetectionModule \n\n\n\n\n\nEnvModule\n\nEnvModule\n\nInfrastructureModule -->\n\nEnvModule->InfrastructureModule\n\n\n\n\n\nDataResponseInterceptor\n\nDataResponseInterceptor\n\nInfrastructureModule -->\n\nDataResponseInterceptor->InfrastructureModule\n\n\n\n\n\nRedisLockService\n\nRedisLockService\n\nRedisModule -->\n\nRedisLockService->RedisModule\n\n\n\n\n\nRedisService\n\nRedisService\n\nRedisModule -->\n\nRedisService->RedisModule\n\n\n\n\n\nJwtStrategy\n\nJwtStrategy\n\nSecurityModule -->\n\nJwtStrategy->SecurityModule\n\n\n\n\n\nSessionsService\n\nSessionsService\n\nSessionsModule -->\n\nSessionsService->SessionsModule\n\n\n\n\n\nTokenService\n\nTokenService\n\nTokenModule -->\n\nTokenService->TokenModule\n\n\n\n\n\nUsersService\n\nUsersService\n\nUsersModule -->\n\nUsersService->UsersModule\n\n\n\n\n\n\n    \n    \n    \n        Zoom in\n        Reset\n        Zoom out\n    \n\n  \n\n    \n        \n            \n                \n                    \n                    \n                        15 Modules\n                    \n                \n            \n        \n        \n            \n                \n                    \n                    4 Controllers\n                \n            \n        \n        \n            \n                \n                    \n                    2 Entities\n                \n            \n        \n        \n            \n                \n                    \n                    18 Injectables\n                \n            \n        \n       